1043	            if let Resolved::Record { node, ports_prem, .. } = &resolved[n] {
1044	                EndPoint::port(node.clone(), ports_prem[p].clone())
1045	            } else {
1046	                EndPoint::node(resolved[n].node_id().to_string())
1047	            }
