533	/// Assemble a record node's model from a [`RecordSpec`] and its allocated ports.
534	/// Empty premise / conclusion groups are dropped; the info group is always kept
535	/// (matches the observed group structure). Each prem/concl group's cells share the
536	/// record wrap budget by the proportional allocation [`group_widths`]; the info
537	/// cell is its own single-cell group (budget 87). Cell text is wrapped (ragged
538	/// HughesPJ `fill`) and escaped by [`crate::doclayout::wrap_cell_dot`].
539	fn build_record(spec: &RecordSpec, ports_prem: &[String], port_info: &str, ports_concl: &[String]) -> Record {
540	    let mut columns: Vec<Vec<Cell>> = Vec::new();
541	    if !spec.premises.is_empty() {
542	        columns.push(group_cells(&spec.premises, ports_prem, &spec.prem_widths));
543	    }
544	    // The info cell is its own single-cell group (full width), fed through the
545	    // faithful layout engine at [`FILL_WIDTH`].
546	    columns.push(vec![Cell::new(port_info, wrap_cell_dot(&spec.info, FILL_WIDTH as isize))]);
547	    if !spec.conclusions.is_empty() {
548	        columns.push(group_cells(&spec.conclusions, ports_concl, &spec.concl_widths));
549	    }
550	    Record {
551	        columns,
552	        fillcolor: spec.fillcolor.clone(),
553	        fontcolor: spec.fontcolor.clone(),
554	        role: Role(spec.role.clone()),
555	    }
556	}
