326	/// The caller-supplied width interface (round 10): with no overrides the
327	/// result is byte-identical to the estimate path; a supplied occupancy widens
328	/// or narrows SIBLING budgets exactly as the display-text estimate would have;
329	/// a supplied fill numerator moves the wrapped cell's own share.
330	#[test]
331	fn supplied_cell_widths_override_estimates() {
332	    use graph_clean::generate::{group_widths, group_widths_with, CellWidths};
333	    // [Faa 45, Sib 40]: T = 85 <= 87, nothing wraps under estimates.
334	    let cells: Vec<String> = vec![
335	        "Faa( $aa, $ab, $ac, $ad, $ae, $af, $ag, $ah )".into(),
336	        format!("Sib( '{}' )", "a".repeat(33)),
337	    ];
338	    // No-override call sites are byte-identical (regression gate).
339	    assert_eq!(group_widths_with(&cells, &[]), group_widths(&cells));
340	    assert_eq!(group_widths_with(&cells, &[None, None]), group_widths(&cells));
341	    let flat0 = 45usize;
342	    assert!(group_widths(&cells)[0] >= flat0, "estimate path: Faa stays flat");
343	    // Supplying the sib's internal occupancy (say its UN-abbreviated width
344	    // renders at 60 columns) shrinks Faa's budget below its flat: it wraps.
345	    let ov = vec![None, Some(CellWidths::occupancy(60))];
346	    let w = group_widths_with(&cells, &ov);
347	    assert!(w[0] < flat0, "supplied sibling occupancy must trigger the wrap");
348	    // The wrapping cell's own fill share follows the supplied numerator too.
349	    let ov2 = vec![
350	        Some(CellWidths { fill_width: Some(80), ..Default::default() }),
351	        Some(CellWidths::occupancy(60)),
352	    ];
353	    let w2 = group_widths_with(&cells, &ov2);
354	    assert!(w2[0] > w[0], "a larger supplied fill numerator widens the share");
355	    // And a supplied bonus lifts the cell's own trigger budget.
356	    let ov3 = vec![
357	        Some(CellWidths { bonus: Some(30), ..Default::default() }),
358	        Some(CellWidths::occupancy(60)),
359	    ];
360	    let w3 = group_widths_with(&cells, &ov3);
361	    assert!(w3[0] >= flat0, "a supplied bonus can keep the cell flat");
362	}
