398	/// Build a plain `name( LONG, $aa, … )` argfact of an exact display width,
399	/// mirroring the round-8..11 probe generators.
400	fn probe_argfact(name: &str, flat: usize) -> String {
401	    let k = (flat - name.len() - 8) / 5;
402	    let l1 = flat - name.len() - 4 - 5 * k;
403	    let long = format!("$q{}", "a".repeat(l1 - 2));
404	    let mut elems = vec![long];
405	    let a = "abcdefghijklmnopqrstuvwxyz".as_bytes();
406	    for i in 0..k {
407	        elems.push(format!("${}{}", a[i / 26] as char, a[i % 26] as char));
408	    }
409	    let s = format!("{}( {} )", name, elems.join(", "));
410	    assert_eq!(s.chars().count(), flat);
411	    s
412	}
