1	//! Shared test-only ingest: a minimal parser for the exact DOT dialect the
2	//! tamarin web UI emits, reading a captured payload into the crate's [`Graph`]
3	//! model. Used by both the round-trip and allocator corpus tests. Not part of the
4	//! crate's public API — this is observation tooling, not the reimplementation.
5	#![allow(dead_code)]
6	
7	use graph_clean::model::*;
8	
9	/// Merge a plain-node legend that spans several physical lines into one logical
10	/// line, so every statement is a single element.
11	pub fn logical_lines(dot: &str) -> Vec<String> {
12	    let raw: Vec<&str> = dot.split('\n').collect();
13	    let mut out: Vec<String> = Vec::new();
14	    let mut i = 0;
15	    while i < raw.len() {
16	        let line = raw[i];
17	        if line.contains("shape=\"plain\"") && !line.trim_end().ends_with("];") {
18	            let mut buf = String::from(line);
19	            i += 1;
20	            loop {
21	                buf.push('\n');
22	                buf.push_str(raw[i]);
23	                if raw[i].trim_end().ends_with("];") {
24	                    break;
25	                }
26	                i += 1;
27	            }
28	            out.push(buf);
29	            i += 1;
30	        } else {
31	            out.push(line.to_string());
32	            i += 1;
33	        }
34	    }
35	    out
36	}
37	
38	pub fn parse(dot: &str) -> Graph {
39	    let lines = logical_lines(dot);
40	    let header = if lines.iter().any(|l| l == "packmode=\"cluster\";") {
41	        Header::Compact
42	    } else {
43	        Header::Simple
44	    };
45	    let mut idx = lines.iter().position(|l| l == "digraph \"G\" {").unwrap() + 1;
46	    let mut g = Graph::new(header);
47	    g.body = parse_block(&lines, &mut idx);
48	    g
49	}
50	
51	fn parse_block(lines: &[String], idx: &mut usize) -> Vec<Stmt> {
52	    let mut out = Vec::new();
53	    while *idx < lines.len() {
54	        let line = lines[*idx].clone();
55	        let trimmed = line.trim_end();
56	        if trimmed == "}" {
57	            *idx += 1;
58	            return out;
59	        }
60	        if trimmed.is_empty() || is_block_attr(trimmed) {
61	            *idx += 1;
62	            continue;
63	        }
64	        if trimmed.starts_with("subgraph \"cluster_") {
65	            let label = trimmed
66	                .trim_start_matches("subgraph \"cluster_")
67	                .trim_end_matches("\" {")
68	                .to_string();
69	            *idx += 1;
70	            let color = capture_attr(lines, *idx, "color").unwrap();
71	            let body = parse_block(lines, idx);
72	            out.push(Stmt::Cluster(Cluster { label, color, body }));
73	            continue;
74	        }
75	        if trimmed == "{" {
76	            *idx += 1;
77	            let rank = capture_attr(lines, *idx, "rank").unwrap();
78	            let body = parse_block(lines, idx);
79	            out.push(Stmt::RankBlock(RankBlock { rank, body }));
80	            continue;
81	        }
82	        if line.contains(" -> ") {
83	            out.push(Stmt::Edge(parse_edge(&line)));
84	        } else {
85	            out.push(Stmt::Node(parse_node(&line)));
86	        }
87	        *idx += 1;
88	    }
89	    out
90	}
91	
92	fn is_block_attr(l: &str) -> bool {
93	    if l.starts_with("node[") || l.starts_with("edge[") {
94	        return true;
95	    }
96	    if l.contains('[') {
97	        return false;
98	    }
99	    if let Some(eq) = l.find('=') {
100	        let key = &l[..eq];
101	        return key.chars().all(|c| c.is_ascii_lowercase() || c.is_ascii_digit()) && l.ends_with(';');
102	    }
103	    false
104	}
105	
106	fn capture_attr(lines: &[String], from: usize, key: &str) -> Option<String> {
107	    let needle = format!("{}=\"", key);
108	    for l in &lines[from..] {
109	        let t = l.trim();
110	        if t.starts_with(&needle) {
111	            let rest = &t[needle.len()..];
112	            return Some(rest.trim_end_matches("\";").trim_end_matches('"').to_string());
113	        }
114	        if t == "}" {
115	            break;
116	        }
117	    }
118	    None
119	}
120	
121	fn parse_node(line: &str) -> Node {
122	    let l = line.trim_end();
123	    let br = l.find('[').unwrap();
124	    let id = l[..br].to_string();
125	    let attrs = &l[br + 1..l.rfind("];").unwrap()];
126	    if attrs.starts_with("shape=\"record\"") {
127	        let label_start = l.find(",label=\"").unwrap() + ",label=\"".len();
128	        let label_end = l.find("\",fillcolor=\"").unwrap();
129	        let label = &l[label_start..label_end];
130	        let fillcolor = extract(l, "fillcolor=\"");
131	        let fontcolor = extract(l, "fontcolor=\"");
132	        let role = extract(l, "role=\"");
133	        Node::record(
134	            id,
135	            Record { columns: parse_record_label(label), fillcolor, fontcolor, role: Role(role) },
136	        )
137	    } else if attrs.starts_with("shape=\"plain\"") {
138	        let start = l.find("label=<").unwrap() + "label=<".len();
139	        let end = l.rfind(">];").unwrap();
140	        Node::plain(id, &l[start..end])
141	    } else {
142	        let label_start = l.find("label=\"").unwrap() + "label=\"".len();
143	        let label_end = l.find("\",shape=\"").unwrap();
144	        let label = l[label_start..label_end].to_string();
145	        let shape = extract(l, "shape=\"");
146	        let color = if l.contains(",color=\"") { Some(extract(l, ",color=\"")) } else { None };
147	        if shape == "ellipse" {
148	            Node::ellipse(id, Ellipse { label, color })
149	        } else {
150	            Node::shaped(id, Shaped { label, shape, color })
151	        }
152	    }
153	}
154	
155	fn extract(l: &str, key: &str) -> String {
156	    let s = l.find(key).unwrap() + key.len();
157	    let rest = &l[s..];
158	    let e = rest.find('"').unwrap();
159	    rest[..e].to_string()
160	}
161	
162	fn parse_record_label(s: &str) -> Vec<Vec<Cell>> {
163	    let inner = &s[1..s.len() - 1];
164	    split_top(inner, '|')
165	        .into_iter()
166	        .map(|group| {
167	            let g = &group[1..group.len() - 1];
168	            split_top(g, '|').into_iter().map(|cell| parse_cell(&cell)).collect()
169	        })
170	        .collect()
171	}
172	
173	fn parse_cell(cell: &str) -> Cell {
174	    let gt = find_unescaped(cell, '>').unwrap();
175	    let port = cell[1..gt].to_string();
176	    let text = cell[gt + 2..].to_string();
177	    Cell { port, text }
178	}
179	
180	fn split_top(s: &str, sep: char) -> Vec<String> {
181	    let mut parts = Vec::new();
182	    let mut depth = 0i32;
183	    let mut cur = String::new();
184	    let mut esc = false;
185	    for c in s.chars() {
186	        if esc {
187	            cur.push(c);
188	            esc = false;
189	            continue;
190	        }
191	        match c {
192	            '\\' => {
193	                cur.push(c);
194	                esc = true;
195	            }
196	            '{' => {
197	                depth += 1;
198	                cur.push(c);
199	            }
200	            '}' => {
201	                depth -= 1;
202	                cur.push(c);
203	            }
204	            _ if c == sep && depth == 0 => {
205	                parts.push(std::mem::take(&mut cur));
206	            }
207	            _ => cur.push(c),
208	        }
209	    }
210	    parts.push(cur);
211	    parts
212	}
213	
214	fn find_unescaped(s: &str, target: char) -> Option<usize> {
215	    let mut esc = false;
216	    for (i, c) in s.char_indices() {
217	        if esc {
218	            esc = false;
219	            continue;
220	        }
221	        if c == '\\' {
222	            esc = true;
223	        } else if c == target {
224	            return Some(i);
225	        }
226	    }
227	    None
228	}
229	
230	fn parse_edge(line: &str) -> Edge {
231	    let l = line.trim_end().trim_end_matches(';');
232	    let arrow = l.find(" -> ").unwrap();
233	    let src = parse_endpoint(&l[..arrow]);
234	    let rest = &l[arrow + 4..];
235	    let (dst_str, attrs) = match rest.find('[') {
236	        Some(b) => (&rest[..b], parse_attrs(&rest[b + 1..rest.rfind(']').unwrap()])),
237	        None => (rest, Vec::new()),
238	    };
239	    Edge { src, dst: parse_endpoint(dst_str), attrs }
240	}
241	
242	fn parse_endpoint(s: &str) -> EndPoint {
243	    match s.find(':') {
244	        Some(c) => EndPoint::port(s[..c].to_string(), s[c + 1..].to_string()),
245	        None => EndPoint::node(s.to_string()),
246	    }
247	}
248	
249	fn parse_attrs(s: &str) -> Vec<(String, String)> {
250	    let mut out = Vec::new();
251	    for part in s.split("\",") {
252	        let part = part.trim_end_matches('"');
253	        if let Some(eq) = part.find("=\"") {
254	            out.push((part[..eq].to_string(), part[eq + 2..].to_string()));
255	        }
256	    }
257	    out
258	}
