1	//! Corpus validation of the node-id/port ALLOCATOR (BEHAVIOR.md §3e, item 3).
2	//!
3	//! Re-uses the round-trip parser to read a captured graph into the model (which
4	//! preserves the original `n<K>` ids and ports), then re-derives every id from
5	//! scratch with [`NodeIdAllocator`] by walking the statements in emission order.
6	//! If the allocator's scheme is right, the re-derived ids equal the captured
7	//! ones for every node and every port.
8	//!
9	//! Off by default; set `GRAPHCLEAN_CORPUS` to a directory of `*.dot` payloads.
10	//! The six committed fixtures are always checked by `alloc_fixtures`.
11	
12	use graph_clean::alloc::NodeIdAllocator;
13	use graph_clean::model::*;
14	
15	#[path = "parse_util.rs"]
16	mod parse_util;
17	use parse_util::parse;
18	
19	/// Walk `stmts` in emission order, allocating ids, and assert they match the ids
20	/// the parser preserved from the payload. Recurses into clusters / rank blocks at
21	/// their position (the global counter does not reset).
22	fn check_alloc(stmts: &[Stmt], alloc: &mut NodeIdAllocator) -> Result<(), String> {
23	    for s in stmts {
24	        match s {
25	            Stmt::Node(n) => match &n.kind {
26	                NodeKind::Record(r) => {
27	                    let n_cells: usize = r.columns.iter().map(|c| c.len()).sum();
28	                    let ids = alloc.record(n_cells);
29	                    // ports, in cell order across groups
30	                    let mut got_ports = ids.ports.into_iter();
31	                    for col in &r.columns {
32	                        for cell in col {
33	                            let want = got_ports.next().unwrap();
34	                            if cell.port != want {
35	                                return Err(format!("port {} != {}", cell.port, want));
36	                            }
37	                        }
38	                    }
39	                    if n.id != ids.node {
40	                        return Err(format!("record node {} != {}", n.id, ids.node));
41	                    }
42	                }
43	                _ => {
44	                    let id = alloc.node();
45	                    if n.id != id {
46	                        return Err(format!("node {} != {}", n.id, id));
47	                    }
48	                }
49	            },
50	            Stmt::Cluster(c) => check_alloc(&c.body, alloc)?,
51	            Stmt::RankBlock(b) => check_alloc(&b.body, alloc)?,
52	            Stmt::Edge(_) => {}
53	        }
54	    }
55	    Ok(())
56	}
57	
58	fn check_payload(dot: &str) -> Result<(), String> {
59	    let g = parse(dot);
60	    let mut alloc = NodeIdAllocator::new();
61	    check_alloc(&g.body, &mut alloc)
62	}
63	
64	#[test]
65	fn alloc_fixtures() {
66	    for (name, dot) in [
67	        ("simple_ports", include_str!("fixtures/simple_ports.dot") as &str),
68	        ("simple_abbrev", include_str!("fixtures/simple_abbrev.dot")),
69	        ("compact_clusters", include_str!("fixtures/compact_clusters.dot")),
70	        ("compact_abbrev", include_str!("fixtures/compact_abbrev.dot")),
71	        ("multi_abbrev", include_str!("fixtures/multi_abbrev.dot")),
72	        ("nsl_invtrap", include_str!("fixtures/nsl_invtrap.dot")),
73	        ("invtrap_compressed", include_str!("fixtures/invtrap_compressed.dot")),
74	    ] {
75	        check_payload(dot).unwrap_or_else(|e| panic!("alloc mismatch in {name}: {e}"));
76	    }
77	}
78	
79	#[test]
80	fn alloc_corpus_dir() {
81	    let Ok(dir) = std::env::var("GRAPHCLEAN_CORPUS") else {
82	        return;
83	    };
84	    let (mut total, mut ok) = (0usize, 0usize);
85	    let mut fails: Vec<String> = Vec::new();
86	    for entry in std::fs::read_dir(&dir).unwrap() {
87	        let path = entry.unwrap().path();
88	        if path.extension().and_then(|e| e.to_str()) != Some("dot") {
89	            continue;
90	        }
91	        let dot = std::fs::read_to_string(&path).unwrap();
92	        total += 1;
93	        match std::panic::catch_unwind(|| check_payload(&dot)) {
94	            Ok(Ok(())) => ok += 1,
95	            other if fails.len() < 20 => {
96	                fails.push(format!("{}: {:?}", path.file_name().unwrap().to_string_lossy(), other));
97	            }
98	            _ => {}
99	        }
100	    }
101	    eprintln!("allocator corpus check: {ok}/{total} byte-consistent");
102	    for f in &fails {
103	        eprintln!("  MISMATCH {f}");
104	    }
105	    assert_eq!(ok, total, "{} of {} graphs violated the allocation scheme", total - ok, total);
106	}
